#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int search(vector<int>& A, int x, int k, int n) {
        int left = 0, right = n - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (A[mid] == x) {
                return mid;
            } else if (A[mid] > x) {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return -1;
    }
};

int main() {
    int n, k, x;
    cin >> n;
    vector<int> A(n);
    for (int i = 0; i < n; ++i) {
        cin >> A[i];
    }
    cin >> k >> x;
    Solution s;
    cout << s.search(A, x, k, n) << endl;
    return 0;
}
